var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"크르르르…….","JPN":"ガルルル……","ENG":"Grrrr...","TWN":"呃呃呃呃……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_05"},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러고 보니, 당신들에게는 아직 이렇다 할 이름이 없군요.","JPN":"そういえば、あなたたちにはまだこれと言った名前がありませんね。","ENG":"Now that I think of it, you have no name.","TWN":"這麼說來，你們還沒有一個正式的名字呢。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"이름……?","JPN":"名前……？","ENG":"Name...?","TWN":"名字……?"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 누구나 무대 위에 서려면, 그에 걸맞은 이름이 필요한 법이니까요.","JPN":"ええ。誰でも舞台に立つのなら、それに見合った名前が必要なのですよ。","ENG":"Yes. To stand on stage, one must have a suitable name.","TWN":"是的。任何人想要站在舞台上，都需要一個合適的名字。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"이름. 인간의 기준.","JPN":"名前。人間ノ基準。","ENG":"Name. Human standards.","TWN":"名字。人類的標準。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"이해할 수 없다.","JPN":"理解デキナイ。","ENG":"Cannot understand.","TWN":"我。無法理解。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇지만도 않습니다. 무대 위에서 이름은 곧 배역.","JPN":"そんなことありません。舞台において名前はすなわち役名。","ENG":"That's not true. On stage, a name is your role.","TWN":"也不儘然。在舞台上，名字就是你的角色。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이름을 가진 배역은 이름 없는 엑스트라와는 명백히 다르니까요.","JPN":"役名を持つ者は、名もなきエキストラとは確かに違います。","ENG":"There is a clear difference between a role with a name and a background character.","TWN":"有名字的角色顯然和沒有名字的龍套不同。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들의 정체가 무엇인지 속단하기는 이르지만, 보통 침식체와는 다른 특징을 보이죠.","JPN":"あなたたちの正体が何なのかまでは判断できませんが、普通の侵食体とは異なる特徴が見られます。","ENG":"Though it's too early to tell what you really are, you do show some characteristics that stand out from ordinary C.O.s.","TWN":"雖然現在判斷身份還為時過早，但你們表現出了與普通侵蝕體不同的特徵。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자의식을 가지고 있다는 점, 의도적으로 침식현상을 발생시킬 수 있다는 점…….","JPN":"自我を持ち、意図的に侵食現象を起こせるという点……","ENG":"For one, you are self-conscious. And another being that you can cause a Counterside Effect at will...","TWN":"具有自我意識，能夠有意引發侵蝕現象……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 다른 존재로부터 가능성을 빼앗아, 진화를 반복한다는 점.","JPN":"そして、他の存在から可能性を奪い、進化し続けるという点。","ENG":"Also, you steal possibilities from other entities and evolve.","TWN":"而且能從其他存在那裡奪取可能性，不斷進行進化。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면, 역시 당신들에게는 이용가치가 있어요.","JPN":"やはり、あなたたちには利用価値があります。","ENG":"It seems that you will be useful to me.","TWN":"那麼，果然你們還是有利用價值的。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들의 목적이 세계의 가능성을 <color=#ffd34c>수확</color>하는 것이라면.","JPN":"あなたたちの目的が世界の可能性を<color=#ffd34c>収穫</color>することなら。","ENG":"If your goal is to <color=#ffd34c>harvest</color> the possibilities of this world,","TWN":"你們的目的是收穫世界的可能性。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 각본에 당신이 맡을 배역을 하나 준비해두죠.","JPN":"あなたの務める役を、私の脚本に用意しておきましょう。","ENG":"I shall prepare a role for you in my script.","TWN":"我可以為你在我的劇本裡準備一個角色。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 무대 위에 설 수 있도록.","JPN":"あなたが舞台に立つことができるように。","ENG":"So that you may also stand on stage.","TWN":"讓你能夠站上舞台。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"수확자, <color=#ffd34c>하베스터</color>…….","JPN":"収穫する者、<color=#ffd34c>ハーベスター</color>……","ENG":"Your name will be <color=#ffd34c>Harvester</color>–","TWN":"收穫者, 不，<color=#ffd34c>收割者</color>……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 위력. 익히는 게 빠르군요.","JPN":"この威力……習得が早いですね。","ENG":"That power. A quick learner, I see.","TWN":"這威力，學得真快啊。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"코핀 컴퍼니의 저격수의 공격을 모방한 건가요?","JPN":"コフィンカンパニーのスナイパーの攻撃を模倣しているのですか？","ENG":"Did you just imitate Coffin Company's sniper's attack?","TWN":"是模仿科芬公司狙擊手的攻擊嗎？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"얻었다. 경험. 인간의 무기.","JPN":"得ラレタ。経験。人間ノ武器。","ENG":"I gained. Experience. Human's weapon.","TWN":"得到了。經驗。人類的武器。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"강해졌다. 너와 싸울 때보다.","JPN":"強クナッタ。オマエト戦ッタ時ヨリ。","ENG":"I am stronger. Than when I fought you.","TWN":"比那時。變強了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"탐한다. 너의 가능성.","JPN":"欲シイ。オマエノ可能性。","ENG":"I crave. Your possibilities.","TWN":"想要。你的可能性。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"죽는다. 몇 번이든지.","JPN":"死ヌ。何度デモ。","ENG":"I die. Many times.","TWN":"死。無論多少次。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"죽이기 위해서라면.","JPN":"殺スタメナラ。","ENG":"In order to kill.","TWN":"為了。殺掉。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"죽음이라…….","JPN":"死、ですか……","ENG":"Death...","TWN":"死亡嗎……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 알고 계신가요? 죽음으로도 결코 거스를 수 없는 게 있답니다.","JPN":"でも、ご存じですか？　死をもってしても決して逆らえないものがあるんですよ。","ENG":"Did you know? There are some things that even death can't defy.","TWN":"但是你知道嗎？有些東西即使是死亡也無法藐視。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"바로 <color=#ffd34c>절망</color>이죠.","JPN":"それは<color=#ffd34c>絶望</color>です。","ENG":"And that is <color=#ffd34c>despair</color>.","TWN":"那種東西，正是<color=#ffd34c>絕望</color>。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"절망?","JPN":"絶望？","ENG":"Despair?","TWN":"絕望？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 소개가 늦었군요.","JPN":"自己紹介が遅れましたね。","ENG":"I apologize for my late introduction.","TWN":"很抱歉介紹遲了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 이름은 스완……. 스완 클레어.","JPN":"私の名はスワン……スワン・クレア。","ENG":"I am Swan... Swan Claire.","TWN":"我是史旺……史旺·克萊爾。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금부터 각본가로서 당신에게 절망을 각인시켜드리죠.","JPN":"今から脚本家として、あなたに絶望を刻んで差し上げます。","ENG":"From now on, I will imprint despair in you as a scriptwriter.","TWN":"從現在開始，作為編劇，我會讓你銘記住這種感覺。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};